package com.pixmaprenderer;

import com.badlogic.gdx.Files;
import com.badlogic.gdx.backends.headless.HeadlessApplication;
import com.badlogic.gdx.backends.headless.HeadlessApplicationConfiguration;
import com.badlogic.gdx.files.FileHandle;

import java.io.IOException;

public class Main {

    public static void main(String[] args) {
        if (args.length < 2) {
            System.err.println("Usage: pixmap-renderer <input_file> <output_png>");
            System.exit(1);
        }

        String inputPath = args[0];
        String outputPath = args[1];

        // Read the input file before booting libGDX (file I/O is fine from any thread)
        String inputContent;
        try {
            // Use absolute path resolution since we're not yet inside GDX context
            inputContent = new String(java.nio.file.Files.readAllBytes(java.nio.file.Paths.get(inputPath)));
        } catch (IOException e) {
            System.err.println("ERROR: Cannot read input file: " + inputPath);
            e.printStackTrace(System.err);
            System.exit(1);
            return;
        }

        HeadlessApplicationConfiguration config = new HeadlessApplicationConfiguration();
        HeadlessPixmapRenderer listener = new HeadlessPixmapRenderer(inputContent, outputPath);

        HeadlessApplication app = new HeadlessApplication(listener, config);

        // Wait for the headless app to finish (listener calls Gdx.app.exit())
        try {
            app.getApplicationListener();
            // The headless application runs on a daemon thread; we need to join it
            // The simplest approach: loop until exit is called
            while (true) {
                Thread.sleep(100);
            }
        } catch (InterruptedException e) {
            // Expected — the headless thread exits and interrupts us
        }
    }
}

